  8	import ConfigurePerformance, {
  9	  ProfileRequirementsText,
 10	} from './configure-performance';
 11	
 12	jest.mock('@odf/core/hooks', () => ({
 13	  useNodesData: jest.fn(),
 14	}));
 15	
 16	const onResourceProfileChange = jest.fn();
 17	
 18	const errorIconSelector = '.pf-v6-c-menu-toggle__status-icon';
 19	
 20	describe('Configure Performance', () => {
 21	  beforeEach(() => {
 22	    onResourceProfileChange.mockClear();
 23	  });
 24	
 25	  it('renders default profile and selects Performance profile', async () => {
 26	    const cpu = 12;
 27	    const memory = 32 * 1000 * 1000 * 1000;
 28	    const nodes = createFakeNodesData(3, cpu, memory);
 29	    const selectedNodes = createWizardNodeState(nodes);
 30	    (useNodesData as jest.Mock).mockReturnValueOnce([nodes, true, null]);
 31	
 32	    const user = userEvent.setup();
 33	    const { container } = render(
 34	      <ConfigurePerformance
 35	        onResourceProfileChange={onResourceProfileChange}
 36	        resourceProfile={ResourceProfile.Balanced}
 37	        selectedNodes={selectedNodes}
 38	      />
 39	    );
 40	
 41	    const dropdown = screen.getByRole('button', {
 42	      name: /select a performance mode from the list/i,
 43	    });
 44	    expect(dropdown).toHaveTextContent('{{mode}} mode');
 45	
 46	    const errorIcon = container.querySelector(errorIconSelector);
 47	    expect(errorIcon).toBeFalsy();
 48	
 49	    await user.click(dropdown);
 50	    const performanceOption = screen
 51	      .getByTestId('Performance mode')
 52	      .querySelector('button') as HTMLButtonElement;
 53	    await user.click(performanceOption);
 54	    expect(onResourceProfileChange).toHaveBeenNthCalledWith(
 55	      1,
 56	      ResourceProfile.Performance
 57	    );
 58	  });
 59	
 60	  it('forces Lean when selectable nodes do not allow higher profiles', () => {
 61	    (useNodesData as jest.Mock).mockReturnValueOnce([[], true, null]);
 62	
 63	    render(
 64	      <ConfigurePerformance
 65	        onResourceProfileChange={onResourceProfileChange}
 66	        resourceProfile={ResourceProfile.Balanced}
 67	        selectedNodes={[]}
 68	      />
 69	    );
 70	    expect(onResourceProfileChange).toHaveBeenNthCalledWith(
 71	      1,
 72	      ResourceProfile.Lean
 73	    );
 74	  });
 75	
 76	  it('shows error icon in the dropdown when resource requirements are not enough', () => {
 77	    const cpu = 12;
 78	    const memory = 32 * 1000 * 1000 * 1000;
 79	    const nodes = createFakeNodesData(3, cpu, memory);
 80	    const selectedNodes = createWizardNodeState(nodes);
 81	    (useNodesData as jest.Mock).mockReturnValueOnce([nodes, true, null]);
 82	
 83	    const { container } = render(
 84	      <ConfigurePerformance
 85	        onResourceProfileChange={onResourceProfileChange}
 86	        resourceProfile={ResourceProfile.Performance}
 87	        selectedNodes={selectedNodes}
 88	      />
 89	    );
 90	    const dropdown = screen.getByRole('button', {
 91	      name: /select a performance mode from the list/i,
 92	    });
 93	    expect(dropdown).toHaveTextContent('{{mode}} mode');
 94	
 95	    const errorIcon = container.querySelector(errorIconSelector);
 96	    expect(errorIcon).toBeVisible();
 97	    expect(onResourceProfileChange).toHaveBeenCalledTimes(0);
 98	  });
 99	
100	  it('shows higher resource requirements due to high amount of OSDs', () => {
101	    const cpu = 12;
102	    const memory = 32 * 1000 * 1000 * 1000;
103	    const nodes = createFakeNodesData(3, cpu, memory);
104	    const selectedNodes = createWizardNodeState(nodes);
105	    (useNodesData as jest.Mock).mockReturnValueOnce([nodes, true, null]);
106	
107	    render(
108	      <ConfigurePerformance
109	        onResourceProfileChange={onResourceProfileChange}
110	        resourceProfile={ResourceProfile.Balanced}
111	        selectedNodes={selectedNodes}
112	        osdAmount={9}
113	        profileRequirementsText={ProfileRequirementsText}
114	      />
115	    );
116	
117	    const dropdown = screen.getByRole('button', {
118	      name: /select a performance mode from the list/i,
119	    });
120	    expect(dropdown).toHaveTextContent('{{mode}} mode');
121	    expect(screen.getByText(/42 CPUs/i)).toBeInTheDocument();
122	    expect(screen.getByText(/102 GiB/i)).toBeInTheDocument();
123	  });
124	});

